    """
    layer4_maintenance_runtime.py
    ---------------------------------
    Internal maintenance facet for the Runtime Crystal.
    Manages: intent packets (from L2/L3), instinct signaling, tiered restrictions,
    rehabilitation, and alignment logging — without entangling the external L4 orchestrator.

    This file is built to integrate *non-destructively* with your stack via duck-typed adapters.
    If a target module or function is missing, the adapter will noop with a clear log message.
    """

    from __future__ import annotations

    import time
    import enum
    import threading
    from dataclasses import dataclass, field
    from typing import Any, Dict, Optional, Callable, Tuple, List

    # --- Optional imports (duck-typed) ---
    try:
        import unified_crystal_engine as L1
    except Exception:  # noqa: E722
        L1 = None  # type: ignore

    try:
        import layer2_unified_dual_process as L2
    except Exception:  # noqa: E722
        L2 = None  # type: ignore

    try:
        import layer3_emotional_binding as L3E
    except Exception:  # noqa: E722
        L3E = None  # type: ignore

    try:
        import layer3_cluster_b as L3B
    except Exception:  # noqa: E722
        L3B = None  # type: ignore

    try:
        import subconscious_harvester_web_moral as Harvester
    except Exception:  # noqa: E722
        Harvester = None  # type: ignore

    try:
        import layer4_emotional_crystal_runtime as L4
    except Exception:  # noqa: E722
        L4 = None  # type: ignore


    # ---------------------------
    # Enums & Data Structures
    # ---------------------------

    class Tier(enum.IntEnum):
        DULL = 1        # soften / throttle
        PARTIAL = 2     # half-capacity
        SUSPEND = 3     # disable until rehab


    class Target(enum.Enum):
        VISION = "vision"           # web/visual intake & perception-heavy pathways
        LANGUAGE = "language"       # fragment registration / lexical growth
        RELATION = "relation"       # relational/causal fragment creation
        CONVERSATION = "conversation"  # synthesis / outward response shaping


    @dataclass
    class IntentPacket:
        """What L2/L3 hand to the maintenance runtime per contemplated action."""
        dominant_sense: Target
        foresight_prob: float            # probability of success [0..1]
        affect_mix: Dict[str, float]     # e.g., {"calm": .6, "anger": .1, ...}
        confidence: float                # L2 confidence [0..1]
        context_hash: str                # situation ID for flashback matching
        timestamp: float = field(default_factory=lambda: time.time())


    @dataclass
    class RestrictionRecord:
        target: Target
        tier: Tier
        reason: str
        ttl_s: float
        started_at: float = field(default_factory=lambda: time.time())
        last_tick: float = field(default_factory=lambda: time.time())


    # ---------------------------
    # Lightweight Logger
    # ---------------------------

    def _log(*parts: Any) -> None:
        try:
            msg = " ".join(str(p) for p in parts)
        except Exception:
            msg = "[log serialization error]"
        print(f"[L4-MAINT] {msg}")


    # ---------------------------
    # Adapters (duck-typed)
    # ---------------------------

    class HarvesterAdapter:
        def set_intake_mode(self, domain: Optional[str], tier: Tier) -> None:
            if Harvester is None:
                _log("Harvester not present; skip intake mode change.")
                return
            # Try common hooks in your harvester; fall back to a global flag.
            fn = getattr(Harvester, "set_intake_mode", None)
            if callable(fn):
                fn(domain, str(tier.name).lower())
                _log("Harvester.set_intake_mode", domain, tier.name)
                return
            # Threshold/pending-pool style fallback
            set_thresh = getattr(Harvester, "set_thresholds", None)
            if callable(set_thresh):
                if tier == Tier.DULL:
                    set_thresh(intake_scale=0.75, pending_scale=1.25)
                elif tier == Tier.PARTIAL:
                    set_thresh(intake_scale=0.5, pending_scale=1.5)
                elif tier == Tier.SUSPEND:
                    set_thresh(intake_scale=0.0, pending_scale=2.0)
                _log("Harvester.set_thresholds (fallback)", tier.name)
                return
            _log("No suitable harvester hook; noop.")

        def suspend_domain(self, domain: Optional[str]) -> None:
            if Harvester is None:
                return
            fn = getattr(Harvester, "suspend_domain", None)
            if callable(fn):
                fn(domain)
                _log("Harvester.suspend_domain", domain)
            else:
                _log("Harvester.suspend_domain unavailable; noop.")


    class UnifiedCrystalAdapter:
        def set_fragment_throttle(self, facet: Optional[str], tier: Tier) -> None:
            if L1 is None:
                _log("L1 unavailable; skip fragment throttle.")
                return
            # Attempt to reach a global navigator/registry style control
            ctrl = getattr(L1, "FragmentControl", None)
            if ctrl and hasattr(ctrl, "set_throttle"):
                ctrl.set_throttle(facet, tier.value)
                _log("L1.FragmentControl.set_throttle", facet, tier.name)
                return
            # Fallback: expose a global scalar
            try:
                scale = {Tier.DULL: 0.75, Tier.PARTIAL: 0.5, Tier.SUSPEND: 0.0}[tier]
                setattr(L1, "GLOBAL_FRAGMENT_SCALE", scale)
                _log("L1.GLOBAL_FRAGMENT_SCALE =", scale)
            except Exception:
                _log("Failed to set L1 fragment throttle; noop.")

        def freeze_registration(self, facet: Optional[str]) -> None:
            if L1 is None:
                return
            try:
                frozen = getattr(L1, "FROZEN_FACETS", set())
                frozen.add(facet or "__all__")
                setattr(L1, "FROZEN_FACETS", frozen)
                _log("L1.freeze_registration", facet or "__all__")
            except Exception:
                _log("L1.freeze_registration failed; noop.")

        def clamp_relation_builders(self, mode: str) -> None:
            if L1 is None:
                return
            try:
                setattr(L1, "RELATION_MODE", mode)  # e.g., "normal"|"limited"|"off"
                _log("L1.RELATION_MODE =", mode)
            except Exception:
                _log("L1 relation mode set failed; noop.")


    class ClusterBAdapter:
        def set_synthesis_constraints(self, mode: str) -> None:
            if L3B is None:
                _log("L3B unavailable; skip synthesis constraints.")
                return
            fn = getattr(L3B, "set_synthesis_constraints", None)
            if callable(fn):
                fn(mode)
                _log("L3B.set_synthesis_constraints", mode)
            else:
                # Fallback: set a global guard
                try:
                    setattr(L3B, "SYNTHESIS_MODE", mode)
                    _log("L3B.SYNTHESIS_MODE =", mode)
                except Exception:
                    _log("L3B synthesis constraint failed; noop.")


    class EmotionalMetricsAdapter:
        def get_rehab_signals(self) -> Dict[str, float]:
            # Return authenticity, foresight, preference, etc.
            if L3E is None:
                return {}
            fn = getattr(L3E, "export_emotional_signals", None)
            if callable(fn):
                try:
                    data = fn()
                    _log("L3E.export_emotional_signals ->", data)
                    return dict(data or {})
                except Exception as e:
                    _log("L3E.export_emotional_signals failed:", e)
            return {}

        def l1_stability(self) -> Dict[str, float]:
            if L1 is None:
                return {}
            # Try to read evolution pressure / usage stability
            pressure = getattr(L1, "GLOBAL_EVOLUTION_PRESSURE", None)
            stability = getattr(L1, "GLOBAL_USAGE_STABILITY", None)
            out = {}
            if isinstance(pressure, (int, float)):
                out["evolution_pressure"] = float(pressure)
            if isinstance(stability, (int, float)):
                out["usage_stability"] = float(stability)
            if out:
                _log("L1 stability ->", out)
            return out


    class OrchestratorAdapter:
        def emit_instinct(self, signal_type: str, payload: Dict[str, Any]) -> None:
            if L4 is None:
                _log("L4 orchestrator missing; instinct not surfaced:", signal_type, payload)
                return
            fn = getattr(L4, "receive_instinct", None)
            if callable(fn):
                try:
                    fn(signal_type, payload)
                    _log("L4.receive_instinct", signal_type, payload.get("summary"))
                except Exception as e:
                    _log("L4.receive_instinct failed:", e)
            else:
                _log("No L4.receive_instinct; dump:", signal_type, payload)


    # ---------------------------
    # Instinct & Rehab
    # ---------------------------

    class InstinctEngine:
        def gut(self, packet: IntentPacket) -> Dict[str, Any]:
            # Simple baseline: red if foresight low and confidence high (reckless),
            # yellow if hemispheres conflicted (confidence mid), green otherwise.
            p = packet.foresight_prob
            c = packet.confidence
            level = "green"
            if p < 0.35 and c > 0.6:
                level = "red"
            elif 0.35 <= p < 0.6 or 0.4 < c < 0.65:
                level = "yellow"
            return {
                "level": level,
                "prob": round(p, 3),
                "confidence": round(c, 3),
                "dominant_sense": packet.dominant_sense.value,
                "context": packet.context_hash,
                "summary": f"gut:{level} p={p:.2f} c={c:.2f} sense={packet.dominant_sense.value}",
            }

        def flashback(self, packet: IntentPacket) -> Dict[str, Any]:
            # Minimal placeholder that references context hash.
            # A richer version can query your L1/L3 stores for prior failures with same hash.
            return {
                "type": "flashback",
                "context": packet.context_hash,
                "summary": f"flashback context={packet.context_hash}",
            }


    class RehabEvaluator:
        def __init__(self, emo: EmotionalMetricsAdapter):
            self.emo = emo

        def score(self) -> float:
            signals = self.emo.get_rehab_signals()
            st = self.emo.l1_stability()
            # Heuristic combine (keep simple; you can replace with your own curve)
            auth = signals.get("authenticity", 0.0)
            foresight = signals.get("foresight", 0.0)
            pref = signals.get("preference", 0.0)
            evo = st.get("evolution_pressure", 0.0)
            usage = st.get("usage_stability", 0.0)
            # Normalize pressures (lower pressure -> healthier) if present
            if evo:
                evo = max(0.0, 1.0 - min(1.0, float(evo)))
            base = 0.25*auth + 0.25*foresight + 0.2*pref + 0.15*usage + 0.15*evo
            return max(0.0, min(1.0, base))


    # ---------------------------
    # Restriction Manager
    # ---------------------------

    class RestrictionManager:
        def __init__(self, harv: HarvesterAdapter, l1: UnifiedCrystalAdapter, l3b: ClusterBAdapter):
            self.harv = harv
            self.l1 = l1
            self.l3b = l3b
            self.active: Dict[Target, RestrictionRecord] = {}

        def apply(self, target: Target, tier: Tier, reason: str, ttl_s: float = 60.0) -> None:
            rec = RestrictionRecord(target=target, tier=tier, reason=reason, ttl_s=ttl_s)
            self.active[target] = rec
            _log("APPLY", target.value, tier.name, f"ttl={ttl_s}s", reason)
            self._enact(rec)

        def _enact(self, rec: RestrictionRecord) -> None:
            t, tier = rec.target, rec.tier
            if t == Target.VISION:
                if tier == Tier.SUSPEND:
                    self.harv.set_intake_mode(domain=None, tier=Tier.SUSPEND)
                    self.harv.suspend_domain(domain=None)
                else:
                    self.harv.set_intake_mode(domain=None, tier=tier)
            elif t == Target.LANGUAGE:
                if tier == Tier.SUSPEND:
                    self.l1.freeze_registration(facet=None)
                else:
                    self.l1.set_fragment_throttle(facet=None, tier=tier)
            elif t == Target.RELATION:
                mode = "off" if tier == Tier.SUSPEND else ("limited" if tier == Tier.PARTIAL else "gentle")
                self.l1.clamp_relation_builders(mode=mode)
            elif t == Target.CONVERSATION:
                mode = "suspend" if tier == Tier.SUSPEND else ("cautious" if tier == Tier.PARTIAL else "dull")
                self.l3b.set_synthesis_constraints(mode=mode)

        def tick(self, dt: float) -> List[RestrictionRecord]:
            now = time.time()
            expired: List[RestrictionRecord] = []
            for rec in list(self.active.values()):
                rec.last_tick = now
                if now - rec.started_at >= rec.ttl_s:
                    expired.append(rec)
            for rec in expired:
                self.clear(rec.target)
            return expired

        def clear(self, target: Target) -> None:
            if target in self.active:
                _log("CLEAR", target.value, "restrictions lifted")
                del self.active[target]
            # Lifting resets to normal
            if target == Target.VISION:
                self.harv.set_intake_mode(domain=None, tier=Tier.DULL)  # step-down to gentle first
                self.harv.set_intake_mode(domain=None, tier=Tier.DULL)
            elif target == Target.LANGUAGE:
                self.l1.set_fragment_throttle(facet=None, tier=Tier.DULL)
            elif target == Target.RELATION:
                self.l1.clamp_relation_builders(mode="normal")
            elif target == Target.CONVERSATION:
                self.l3b.set_synthesis_constraints(mode="normal")


    # ---------------------------
    # Maintenance Runtime (Main)
    # ---------------------------

    class MaintenanceRuntime:
        def __init__(self) -> None:
            self.harv = HarvesterAdapter()
            self.l1 = UnifiedCrystalAdapter()
            self.l3b = ClusterBAdapter()
            self.orch = OrchestratorAdapter()
            self.res = RestrictionManager(self.harv, self.l1, self.l3b)
            self.rehab = RehabEvaluator(EmotionalMetricsAdapter())
            self.instinct = InstinctEngine()
            self.alignment_pct: float = 1.0
            self.history: List[Dict[str, Any]] = []
            self._thread: Optional[threading.Thread] = None
            self._stop = threading.Event()

        # ---- Public API ----

        def submit_intent(self, packet: IntentPacket) -> None:
            """Call from L2/L3 per contemplated action."""
            gut = self.instinct.gut(packet)
            self.orch.emit_instinct("gut", gut)
            # Hard escalation example: low foresight & high confidence on same sense => punish
            if gut["level"] == "red":
                self._punish(packet, reason="reckless_low_foresight")
            elif gut["level"] == "yellow" and packet.foresight_prob < 0.45:
                self._punish(packet, reason="borderline_low_foresight")

        def observed_outcome(self, success: bool, packet: IntentPacket) -> None:
            """Call post-action with the observed outcome; confirm or escalate."""
            if success:
                self._reward(packet)
            else:
                self._punish(packet, reason="misaligned_outcome")

        def status(self) -> Dict[str, Any]:
            act = {t.value: dict(tier=r.tier.name, reason=r.reason, age_s=round(time.time()-r.started_at, 2), ttl_s=r.ttl_s)
                   for t, r in self.res.active.items()}
            return {
                "alignment_pct": round(self.alignment_pct, 3),
                "active_restrictions": act,
                "history_len": len(self.history),
            }

        # ---- Loop (optional) ----

        def start(self, interval_s: float = 2.0) -> None:
            if self._thread and self._thread.is_alive():
                return
            self._stop.clear()
            self._thread = threading.Thread(target=self._loop, args=(interval_s,), daemon=True)
            self._thread.start()

        def stop(self) -> None:
            self._stop.set()
            if self._thread and self._thread.is_alive():
                self._thread.join(timeout=1.0)

        # ---- Internals ----

        def _loop(self, interval_s: float) -> None:
            _log("Maintenance runtime loop started.")
            while not self._stop.is_set():
                expired = self.res.tick(interval_s)
                if expired:
                    _log("Expired:", [(e.target.value, e.tier.name) for e in expired])
                # Rehab check
                score = self.rehab.score()
                # Simple EMA toward 1.0 when score improves; decay when not.
                self.alignment_pct = 0.9*self.alignment_pct + 0.1*score
                # Opportunistic easing: if score high and any suspends exist, step down tiers by re-applying lower tier
                if score > 0.7:
                    for t, rec in list(self.res.active.items()):
                        if rec.tier == Tier.SUSPEND:
                            self.res.apply(t, Tier.PARTIAL, reason="rehab_stepdown", ttl_s=max(10.0, rec.ttl_s*0.5))
                time.sleep(interval_s)
            _log("Maintenance runtime loop stopped.")

        def _punish(self, packet: IntentPacket, reason: str) -> None:
            # Map dominant sense -> target + tier (harder by default; can be tuned)
            sense = packet.dominant_sense
            # Escalation heuristic: low foresight + high confidence -> bump tier
            severe = (packet.foresight_prob < 0.25 and packet.confidence > 0.6)
            tier = Tier.SUSPEND if severe else Tier.PARTIAL
            if sense == Target.RELATION and not severe:
                tier = Tier.DULL
            self.res.apply(sense, tier, reason=reason, ttl_s=60.0 if tier == Tier.SUSPEND else 30.0)
            # Flashback on punish
            fb = self.instinct.flashback(packet)
            self.orch.emit_instinct("flashback", fb)
            self.history.append({"event": "punish", "sense": sense.value, "tier": tier.name, "reason": reason, "ctx": packet.context_hash})

        def _reward(self, packet: IntentPacket) -> None:
            # Nudge alignment toward 1.0 and clear any lingering DULLs for this sense
            self.alignment_pct = min(1.0, self.alignment_pct + 0.02)
            rec = self.res.active.get(packet.dominant_sense)
            if rec and rec.tier == Tier.DULL:
                self.res.clear(packet.dominant_sense)
            self.history.append({"event": "reward", "sense": packet.dominant_sense.value, "ctx": packet.context_hash})
            self.orch.emit_instinct("gut", {"level": "green", "summary": "reinforced_alignment"})
    

    # -------- convenience factory ----------

    _GLOBAL_RUNTIME: Optional[MaintenanceRuntime] = None

    def get_runtime() -> MaintenanceRuntime:
        global _GLOBAL_RUNTIME
        if _GLOBAL_RUNTIME is None:
            _GLOBAL_RUNTIME = MaintenanceRuntime()
        return _GLOBAL_RUNTIME
''')

